module RegisterFile(
    input  clock,
    input  reset,
    input  [4:0]  ReadReg1, ReadReg2, WriteReg,
    input  [31:0] WriteData,
    input  RegWrite,
    output [31:0] ReadData1, ReadData2
    );
    reg [31:0] memory_cells [1:31];
    integer i;
    initial begin
        for (i=1; i<32; i=i+1) begin
            memory_cells[i] <= 0;
        end
    end
    always @(posedge clock) begin
        if (reset) begin
            for (i=1; i<32; i=i+1) begin
                memory_cells[i] <= 0;
            end
        end
        else begin
            if (WriteReg != 0)
                memory_cells[WriteReg] <= (RegWrite) ? WriteData : memory_cells[WriteReg];
        end
    end
    assign ReadData1 = (ReadReg1 == 0) ? 32'h00000000 : memory_cells[ReadReg1];
    assign ReadData2 = (ReadReg2 == 0) ? 32'h00000000 : memory_cells[ReadReg2];
endmodule
